            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 3334845700427688434U;
            aOrbiterG = ((aOrbiterG ^ aOrbiterK) ^ 5321886625716518101U) ^ aOrbiterUpdateSaltD[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 7152090209515863339U), 27U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 3548556952630019928U;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 3939349224436786637U;
