            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 13634194136104682453U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterG) ^ 4748677751522589153U) ^ aOrbiterUpdateSaltB[((aIndex + 19U)) & S_SALT1];
