            aWandererB = aWandererB ^ ((RotL64(aPrevious, 11U) + RotL64(aOrbiterH, 11U)) + aOrbiterJ);
            aWandererG = aWandererG + ((RotL64(aCross, 26U) + RotL64(aOrbiterF, 24U)) + aOrbiterI);
