            aOrbiterI = (aWandererB + RotL64(aPrevious, 29U)) + 10632120695285059342U;
            aOrbiterK = ((aWandererC + RotL64(aIngress, 21U)) + 16745205088323593626U) + aOrbiterAssignSaltA[((aIndex + 28U)) & S_SALT1];
            aOrbiterH = (aWandererH + RotL64(aPrevious, 23U)) + 16839292524925322285U;
            aOrbiterF = ((aWandererG + RotL64(aCross, 19U)) + RotL64(aCarry, 23U)) + 8838994602990939901U;
            aOrbiterG = (aWandererI + RotL64(aScatter, 14U)) + 1680595962595357554U;
            aOrbiterB = ((aWandererA + RotL64(aIngress, 37U)) + 14873941344171868574U) + aNonceWordE;
