            aOrbiterK = (aOrbiterK + aOrbiterH) + 3752010373168582730U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterK) ^ 724844077761949941U) ^ aOrbiterUpdateSaltF[((aIndex + 10U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 3002322228828219059U), 41U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 10686292502287126197U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterF) ^ 3766453747033945546U) ^ aNonceWordP;
            aOrbiterI = RotL64((aOrbiterI * 11009589768745486483U), 53U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterB) + 6287313505307732688U) + aOrbiterUpdateSaltE[((aIndex + 15U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 4693494977130477048U;
